class Solution:
    def flatten(self, head: 'Optional[Node]') -> 'Optional[Node]':
        def rec(node):
            tail = node
            cur = node
            while cur:
                nxt = cur.next
                if cur.child:
                    ctail = rec(cur.child)
                    cur.next = cur.child
                    cur.child.prev = cur
                    cur.child = None
                    if nxt:
                        ctail.next = nxt
                        nxt.prev = ctail
                    tail = ctail
                else:
                    tail = cur
                cur = nxt
            return tail
        if head:
            rec(head)
        return head

