class Solution:
    def flatten(self, head: 'Optional[Node]') -> 'Optional[Node]':
        if not head:
            return head
        dummy = Node(0)
        prev = dummy
        stack = [head]
        while stack:
            cur = stack.pop()
            prev.next = cur
            cur.prev = prev
            if cur.next:
                stack.append(cur.next)
            if cur.child:
                stack.append(cur.child)
                cur.child = None
            prev = cur
        dummy.next.prev = None
        return dummy.next

