var flatten = function(head) {
    if (!head) return head;
    const dummy = new Node(0);
    let prev = dummy;
    const stack = [head];
    while (stack.length) {
        const cur = stack.pop();
        prev.next = cur;
        cur.prev = prev;
        if (cur.next) stack.push(cur.next);
        if (cur.child) {
            stack.push(cur.child);
            cur.child = null;
        }
        prev = cur;
    }
    dummy.next.prev = null;
    return dummy.next;
};
